function Recommendations({ recommendations }) {

  if (!recommendations) return null;

  return (

    <div className="card">

      <h2>Recommended Places</h2>

      {
        recommendations.map((place, index) => (

          <div
            key={index}
            className="item"
          >

            <h3>
              {place.place_name}
            </h3>

            <p>
              {place.city},
              {" "}
              {place.state}
            </p>

            <p>
              Type:
              {" "}
              {place.type}
            </p>

          </div>
        ))
      }

    </div>
  );
}

export default Recommendations;
